WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '68a3f3dd-323f-42cb-bade-55dd8454c49f',
    '2025-11-06 14:30:00+00',
    'fireflies',
    '01K8TXMDWDR88GAQ7JTY0X2ZD0',
    'Inside Tracker // New North Weekly Connect',
    '{"Gil","Baylee Gunnell"}'::text[],
    331,
    'https://us02web.zoom.us/j/87632173885?pwd=tg6VuBc6ZqpqwnUGjPIACYH5GrE0KC.1',
    '{"id":"01K8TXMDWDR88GAQ7JTY0X2ZD0","title":"Inside Tracker // New North Weekly Connect","summary":{"notes":"## **Podcast Production and Scheduling**\n\nThe team will pause weekly calls starting next week due to Gil''s travel, maintaining episode flow with planned recordings and edits. (00:00)  \n- **Gil** confirmed he will be in Berlin next week and unable to join calls, prompting cancellation of the next meeting.  \n- He plans to record **two episodes this week**, with one already released and the next expected to be ready within **one week**.  \n- Gil is actively working on guest engagement and pipeline management to sustain episode production through the **end of the year**.  \n- The team agreed to use new vertical clip formats, which will add an extra day to production, but this delay is manageable given current release schedules.  \n\n## **Content Quality and Client Feedback**\n\nPositive client feedback on formatting improvements is fostering new business opportunities and stronger client relationships. (02:31)  \n- Gil shared improved episode formatting with guest **Joy Spain**, who responded positively and is considering starting her own podcast.  \n- The previous guest, **Dr. Komite**, also requested format changes, showing responsiveness to client feedback.  \n- Gil intends to refer potential new clients like Joy Spain to Baylee’s team, expanding client acquisition possibilities.  \n- Baylee confirmed capacity to onboard new clients, signaling readiness for incoming referrals.  \n\n## **Download Metrics and Audience Engagement**\n\nPodcast downloads remain strong, indicating steady audience engagement and growth potential. (04:14)  \n- The show achieved over **40,000 downloads in the last 90 days** and **14,000 in the last 30 days**, signaling healthy listener retention and growth.  \n- These metrics support continued investment in episode production and format innovation to maintain audience interest.  \n\n## **Resource Management and Workflow Adjustments**\n\nAdjusting meeting frequency will help balance workload and align points-based resource allocation with delivery capacity. (04:55)  \n- Baylee highlighted a current **points deficit** where deliveries exceed allocated capacity, risking resource strain.  \n- To address this, the team agreed to shift meetings from weekly to **every other week**, reducing points use to **five points** per meeting cycle.  \n- Gil approved this change, suggesting Slack for ongoing communication to maintain workflow without weekly calls.  \n- This adjustment aims to improve operational efficiency and prevent burnout while sustaining output quality.","outline":null,"keywords":["podcast production","episode delivery","guest engagement","content pipeline","points system","meeting scheduling"],"overview":"- **Podcast Scheduling Changes:** Weekly calls paused next week due to travel; two episodes recorded this week; one released.  \n- **Client Engagement Success:** Positive feedback from clients like Joy Spain is creating new business opportunities and referrals.  \n- **Strong Download Metrics:** Over 40,000 downloads in last 90 days; 14,000 in last 30 days, showcasing audience engagement growth.  \n- **Resource Management Adjustments:** Meetings shifted to bi-weekly to manage workload; each meeting now utilizes five points to reduce strain.  \n- **Operational Efficiency Goals:** Adjustments aim to enhance workflow, prevent burnout, and maintain quality output amid resource constraints.","action_items":"\n**Gil**\nCancel the meeting scheduled for next week due to travel commitments (00:08)\nSend episode document to the team today (03:26)\nSend another episode document to the team tomorrow (03:26)\nContinue to improve guest communication and maintain pipeline for episodes through the end of the year (01:30)\n\n**Baylee Gunnell**\nFinalize and template new vertical clip format to implement for upcoming episodes, requiring one additional day (01:08)\nMonitor and report podcast download metrics regularly (04:14)\nAdjust meeting schedule to biweekly and reduce points allocation accordingly (05:08)\n"},"duration":5.510000228881836,"speakers":[{"id":0,"name":"Gil"},{"id":1,"name":"Baylee Gunnell"}],"sentences":[{"text":"Yeah, for this week.","index":0,"end_time":0.92,"speaker_id":0,"start_time":0.16,"speaker_name":"Gil"},{"text":"I mean next week I will be in Berlin in the country.","index":1,"end_time":5.28,"speaker_id":0,"start_time":0.92,"speaker_name":"Gil"},{"text":"Oh yeah.","index":2,"end_time":6.8,"speaker_id":0,"start_time":5.28,"speaker_name":"Gil"},{"text":"Wow.","index":3,"end_time":8.32,"speaker_id":1,"start_time":7.84,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, yeah.","index":4,"end_time":10.08,"speaker_id":0,"start_time":8.72,"speaker_name":"Gil"},{"text":"So yeah, yeah, maybe let''s cancel next week because I. I won''t be able to take the call.","index":5,"end_time":17.68,"speaker_id":0,"start_time":11.04,"speaker_name":"Gil"},{"text":"Okay.","index":6,"end_time":18.96,"speaker_id":0,"start_time":18.4,"speaker_name":"Gil"},{"text":"And I think that I will be on an airplane or something like that and yeah.","index":7,"end_time":26.57,"speaker_id":0,"start_time":18.96,"speaker_name":"Gil"},{"text":"So yeah, thank you so much for all the help with the Joy Spain episode and all of that.","index":8,"end_time":36.25,"speaker_id":0,"start_time":27.37,"speaker_name":"Gil"},{"text":"So hopefully she''s happy now.","index":9,"end_time":38.81,"speaker_id":0,"start_time":36.41,"speaker_name":"Gil"},{"text":"Yeah, I''m recording an episode today and one tomorrow so I hope so finger crossed that they will come and then we should.","index":10,"end_time":49.61,"speaker_id":0,"start_time":39.21,"speaker_name":"Gil"},{"text":"If we.","index":11,"end_time":50.37,"speaker_id":0,"start_time":49.93,"speaker_name":"Gil"},{"text":"If I''m sending something today, it should be ready in a week or so, correct?","index":12,"end_time":53.93,"speaker_id":0,"start_time":50.37,"speaker_name":"Gil"},{"text":"Yeah, yeah, it should be ready in a week.","index":13,"end_time":57.13,"speaker_id":1,"start_time":55.13,"speaker_name":"Baylee Gunnell"},{"text":"The one delay potentially could be.","index":14,"end_time":61.41,"speaker_id":1,"start_time":57.69,"speaker_name":"Baylee Gunnell"},{"text":"Do you want to use those new vertical clips in the episode you record today?","index":15,"end_time":66.33,"speaker_id":1,"start_time":61.41,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, I think so.","index":16,"end_time":69.25,"speaker_id":0,"start_time":68.17,"speaker_name":"Gil"},{"text":"So that might take longer.","index":17,"end_time":70.81,"speaker_id":0,"start_time":69.25,"speaker_name":"Gil"},{"text":"We just haven''t templatized it yet.","index":18,"end_time":75.69,"speaker_id":1,"start_time":71.69,"speaker_name":"Baylee Gunnell"},{"text":"That should only take us a day to make sure it''s all updated and the team knows.","index":19,"end_time":79.49,"speaker_id":1,"start_time":75.69,"speaker_name":"Baylee Gunnell"},{"text":"So just an extra day to get that.","index":20,"end_time":81.25,"speaker_id":1,"start_time":79.49,"speaker_name":"Baylee Gunnell"},{"text":"All right.","index":21,"end_time":81.89,"speaker_id":1,"start_time":81.25,"speaker_name":"Baylee Gunnell"},{"text":"No, that''s okay because I released the episode yesterday.","index":22,"end_time":85.85,"speaker_id":0,"start_time":81.89,"speaker_name":"Gil"},{"text":"Have almost a week so it should.","index":23,"end_time":87.51,"speaker_id":0,"start_time":86.15,"speaker_name":"Gil"},{"text":"Yeah.","index":24,"end_time":88.55,"speaker_id":0,"start_time":88.07,"speaker_name":"Gil"},{"text":"Okay.","index":25,"end_time":89.27,"speaker_id":1,"start_time":88.71,"speaker_name":"Baylee Gunnell"},{"text":"And I have another recording to tomorrow again if they will come.","index":26,"end_time":94.75,"speaker_id":0,"start_time":90.47,"speaker_name":"Gil"},{"text":"And I''m.","index":27,"end_time":95.67,"speaker_id":0,"start_time":94.75,"speaker_name":"Gil"},{"text":"I''m.","index":28,"end_time":96.07,"speaker_id":0,"start_time":95.67,"speaker_name":"Gil"},{"text":"I learned to communicate with them and all of that before send them the run of show and to.","index":29,"end_time":100.87,"speaker_id":0,"start_time":96.15,"speaker_name":"Gil"},{"text":"To make sure that they are still engaged and I''m working on a few others so.","index":30,"end_time":107.99,"speaker_id":0,"start_time":101.11,"speaker_name":"Gil"},{"text":"So I hope that that''s will go well.","index":31,"end_time":109.83,"speaker_id":0,"start_time":107.99,"speaker_name":"Gil"},{"text":"And yeah, I seen the template and it''s look good and I think that that''s all for me.","index":32,"end_time":118.95,"speaker_id":0,"start_time":112.87,"speaker_name":"Gil"},{"text":"Any, any.","index":33,"end_time":119.91,"speaker_id":0,"start_time":119.03,"speaker_name":"Gil"},{"text":"Any updates from your side?","index":34,"end_time":121.67,"speaker_id":0,"start_time":120.23,"speaker_name":"Gil"},{"text":"Yeah, we can go through them pretty quick.","index":35,"end_time":125.27,"speaker_id":1,"start_time":122.71,"speaker_name":"Baylee Gunnell"},{"text":"So.","index":36,"end_time":126.15,"speaker_id":0,"start_time":125.75,"speaker_name":"Gil"},{"text":"Just hop back here.","index":37,"end_time":129.51,"speaker_id":1,"start_time":128.07,"speaker_name":"Baylee Gunnell"},{"text":"So yeah, just got the episode.","index":38,"end_time":131.55,"speaker_id":1,"start_time":130.07,"speaker_name":"Baylee Gunnell"},{"text":"We already talked about that.","index":39,"end_time":132.47,"speaker_id":1,"start_time":131.55,"speaker_name":"Baylee Gunnell"},{"text":"That is up and you''ll have two more episodes this week and then it sounds like these new designs are approved.","index":40,"end_time":138.91,"speaker_id":1,"start_time":132.47,"speaker_name":"Baylee Gunnell"},{"text":"So we''ll get these implemented and ready to go in your next episodes.","index":41,"end_time":143.54,"speaker_id":1,"start_time":138.91,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, yeah, no, it''s look good.","index":42,"end_time":145.3,"speaker_id":0,"start_time":143.94,"speaker_name":"Gil"},{"text":"I think that your, your team did a good job.","index":43,"end_time":148.02,"speaker_id":0,"start_time":145.3,"speaker_name":"Gil"},{"text":"Yeah, great.","index":44,"end_time":148.98,"speaker_id":1,"start_time":148.18,"speaker_name":"Baylee Gunnell"},{"text":"Thank you.","index":45,"end_time":149.78,"speaker_id":1,"start_time":149.14,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":46,"end_time":151.62,"speaker_id":0,"start_time":151.14,"speaker_name":"Gil"},{"text":"By the way, Reinhardt, the Joy Span I sent her, I''m sharing the now I''m sharing the folder with them.","index":47,"end_time":160.58,"speaker_id":0,"start_time":151.94,"speaker_name":"Gil"},{"text":"Okay.","index":48,"end_time":161.54,"speaker_id":1,"start_time":160.98,"speaker_name":"Baylee Gunnell"},{"text":"And I did it with the one before with the Dr. Komite and they actually looked at it and they said okay, we don''t like the format, let''s adjust it.","index":49,"end_time":173.92,"speaker_id":0,"start_time":162.5,"speaker_name":"Gil"},{"text":"So they adjusted it.","index":50,"end_time":175.04,"speaker_id":0,"start_time":173.92,"speaker_name":"Gil"},{"text":"I shared it with her and she said wow, that''s look amazing.","index":51,"end_time":178.24,"speaker_id":0,"start_time":175.44,"speaker_name":"Gil"},{"text":"And I said yeah, no, it''s not me, it''s company.","index":52,"end_time":182.4,"speaker_id":0,"start_time":178.32,"speaker_name":"Gil"},{"text":"So yeah, so she is considering to start A podcast.","index":53,"end_time":186.84,"speaker_id":0,"start_time":183.92,"speaker_name":"Gil"},{"text":"So she, if she will start I might send her to your direction if you Are you still looking for more.","index":54,"end_time":196.84,"speaker_id":0,"start_time":186.84,"speaker_name":"Gil"},{"text":"Or less Always go.","index":55,"end_time":198.54,"speaker_id":1,"start_time":196.84,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, always.","index":56,"end_time":200.46,"speaker_id":1,"start_time":199.74,"speaker_name":"Baylee Gunnell"},{"text":"I mean we, we work with a lot of clients, but always room for more.","index":57,"end_time":205.82,"speaker_id":1,"start_time":201.5,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":58,"end_time":206.14,"speaker_id":0,"start_time":205.82,"speaker_name":"Gil"},{"text":"Yeah.","index":59,"end_time":206.42,"speaker_id":0,"start_time":206.14,"speaker_name":"Gil"},{"text":"Okay.","index":60,"end_time":206.86,"speaker_id":1,"start_time":206.42,"speaker_name":"Baylee Gunnell"},{"text":"So I will let you know.","index":61,"end_time":208.5,"speaker_id":0,"start_time":206.94,"speaker_name":"Gil"},{"text":"She''s not sure what she''s she want to do next.","index":62,"end_time":210.78,"speaker_id":0,"start_time":208.5,"speaker_name":"Gil"},{"text":"She published a book, Joy Spain, and she asked me for some advice how to, to sell more copies.","index":63,"end_time":218.66,"speaker_id":0,"start_time":211.58,"speaker_name":"Gil"},{"text":"I told her that I''m not an expert in that, but yeah, that''s it for me.","index":64,"end_time":224.79,"speaker_id":0,"start_time":218.66,"speaker_name":"Gil"},{"text":"So to summarize, next week, let''s cancel.","index":65,"end_time":228.71,"speaker_id":0,"start_time":224.95,"speaker_name":"Gil"},{"text":"I will hopefully today I will send you you guys a document with the the new episode and tomorrow another one and I have a good pipeline of more that I''m trying to push into the funnel.","index":66,"end_time":244.99,"speaker_id":0,"start_time":228.71,"speaker_name":"Gil"},{"text":"So we should go there for until the end of the year.","index":67,"end_time":248.07,"speaker_id":0,"start_time":244.99,"speaker_name":"Gil"},{"text":"If again, finger cross if.","index":68,"end_time":250.35,"speaker_id":0,"start_time":248.07,"speaker_name":"Gil"},{"text":"Yeah, nobody is getting a call fit soon.","index":69,"end_time":254.51,"speaker_id":0,"start_time":250.35,"speaker_name":"Gil"},{"text":"Yep.","index":70,"end_time":255.47,"speaker_id":1,"start_time":254.91,"speaker_name":"Baylee Gunnell"},{"text":"Then just last few updates with how your downloads are doing.","index":71,"end_time":260.67,"speaker_id":1,"start_time":257.23,"speaker_name":"Baylee Gunnell"},{"text":"You had over 40,000 downloads the last 90 days.","index":72,"end_time":264.19,"speaker_id":1,"start_time":260.91,"speaker_name":"Baylee Gunnell"},{"text":"14,000 the last 30.","index":73,"end_time":266.11,"speaker_id":1,"start_time":264.509,"speaker_name":"Baylee Gunnell"},{"text":"And then I did want to take just a quick look at your client portal.","index":74,"end_time":272.11,"speaker_id":1,"start_time":267.07,"speaker_name":"Baylee Gunnell"},{"text":"Really quick, just so you could see, um, where we''re at with points.","index":75,"end_time":276.25,"speaker_id":1,"start_time":272.11,"speaker_name":"Baylee Gunnell"},{"text":"You can see like some of the stuff we''ve been working on.","index":76,"end_time":278.57,"speaker_id":1,"start_time":276.25,"speaker_name":"Baylee Gunnell"},{"text":"Between those edits and your weekly meetings, we are in a bit of a points deficit, meaning we''ve delivered more than you''ve had available.","index":77,"end_time":288.45,"speaker_id":1,"start_time":278.57,"speaker_name":"Baylee Gunnell"},{"text":"Um, I haven''t brought this up previously because I, I, I don''t think it''s a, a really big deal, but one thing we could do is if you wanted, we could change this meeting to every other week and then we could just knock this down to five points instead.","index":78,"end_time":306.66,"speaker_id":1,"start_time":289.49,"speaker_name":"Baylee Gunnell"},{"text":"If that, if that''s good with you.","index":79,"end_time":308.82,"speaker_id":1,"start_time":307.14,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, yeah, no, yeah, we can send it to every other week and we can communicate on Slack.","index":80,"end_time":314.66,"speaker_id":0,"start_time":308.9,"speaker_name":"Gil"},{"text":"That''s fine.","index":81,"end_time":315.22,"speaker_id":0,"start_time":314.66,"speaker_name":"Gil"},{"text":"Okay, perfect.","index":82,"end_time":316.66,"speaker_id":1,"start_time":315.46,"speaker_name":"Baylee Gunnell"},{"text":"Sounds good.","index":83,"end_time":317.46,"speaker_id":1,"start_time":316.82,"speaker_name":"Baylee Gunnell"},{"text":"Excellent.","index":84,"end_time":318.899,"speaker_id":0,"start_time":318.1,"speaker_name":"Gil"},{"text":"Thank you so much, Bailey.","index":85,"end_time":320.5,"speaker_id":0,"start_time":319.14,"speaker_name":"Gil"},{"text":"Have a great day and enjoy the weekend.","index":86,"end_time":323.38,"speaker_id":0,"start_time":320.58,"speaker_name":"Gil"},{"text":"You too.","index":87,"end_time":324.18,"speaker_id":1,"start_time":323.62,"speaker_name":"Baylee Gunnell"},{"text":"We''ll talk later.","index":88,"end_time":324.98,"speaker_id":1,"start_time":324.18,"speaker_name":"Baylee Gunnell"},{"text":"Bye.","index":89,"end_time":325.94,"speaker_id":1,"start_time":325.46,"speaker_name":"Baylee Gunnell"}],"dateString":"2025-11-06T14:30:00.000Z","host_email":"baylee.gunnell@marketersindemand.com","meeting_link":"https://us02web.zoom.us/j/87632173885?pwd=tg6VuBc6ZqpqwnUGjPIACYH5GrE0KC.1","participants":["gil@segterra.com,baylee.gunnell@marketersindemand.com","gil@segterra.com"],"transcript_url":"https://app.fireflies.ai/view/01K8TXMDWDR88GAQ7JTY0X2ZD0","organizer_email":"baylee.gunnell@marketersindemand.com"}'::jsonb,
    '{"label":"positive","confidence":0.87,"bullets":["Agreed to cancel next week''s meeting due to Gil''s travel and meet biweekly going forward.","Gil confirmed two episodes are being recorded this week with more in the pipeline through year-end.","New designs for vertical clips were approved and will be implemented in upcoming episode edits.","Baylee flagged a minor points deficit; both parties agreed to shift meetings to biweekly to offset.","Download metrics strong: 40,000 in last 90 days, with 14,000 in the past 30 alone."],"highlights":[{"quote":"Hopefully today I will send you guys a document with the new episode and tomorrow another one","speaker":"Gil"},{"quote":"You had over 40,000 downloads the last 90 days","speaker":"Baylee Gunnell"},{"quote":"We could change this meeting to every other week and then we could just knock this down","speaker":"Baylee Gunnell"}],"topics":["delivery","planning","metrics"],"model":"openai/gpt-4-1106-preview","version":1,"generated_at":"2025-11-13T00:00:00Z"}'::jsonb,
    '{"fireflies_summary":{"notes":"## **Podcast Production and Scheduling**\n\nThe team will pause weekly calls starting next week due to Gil''s travel, maintaining episode flow with planned recordings and edits. (00:00)  \n- **Gil** confirmed he will be in Berlin next week and unable to join calls, prompting cancellation of the next meeting.  \n- He plans to record **two episodes this week**, with one already released and the next expected to be ready within **one week**.  \n- Gil is actively working on guest engagement and pipeline management to sustain episode production through the **end of the year**.  \n- The team agreed to use new vertical clip formats, which will add an extra day to production, but this delay is manageable given current release schedules.  \n\n## **Content Quality and Client Feedback**\n\nPositive client feedback on formatting improvements is fostering new business opportunities and stronger client relationships. (02:31)  \n- Gil shared improved episode formatting with guest **Joy Spain**, who responded positively and is considering starting her own podcast.  \n- The previous guest, **Dr. Komite**, also requested format changes, showing responsiveness to client feedback.  \n- Gil intends to refer potential new clients like Joy Spain to Baylee’s team, expanding client acquisition possibilities.  \n- Baylee confirmed capacity to onboard new clients, signaling readiness for incoming referrals.  \n\n## **Download Metrics and Audience Engagement**\n\nPodcast downloads remain strong, indicating steady audience engagement and growth potential. (04:14)  \n- The show achieved over **40,000 downloads in the last 90 days** and **14,000 in the last 30 days**, signaling healthy listener retention and growth.  \n- These metrics support continued investment in episode production and format innovation to maintain audience interest.  \n\n## **Resource Management and Workflow Adjustments**\n\nAdjusting meeting frequency will help balance workload and align points-based resource allocation with delivery capacity. (04:55)  \n- Baylee highlighted a current **points deficit** where deliveries exceed allocated capacity, risking resource strain.  \n- To address this, the team agreed to shift meetings from weekly to **every other week**, reducing points use to **five points** per meeting cycle.  \n- Gil approved this change, suggesting Slack for ongoing communication to maintain workflow without weekly calls.  \n- This adjustment aims to improve operational efficiency and prevent burnout while sustaining output quality.","outline":null,"keywords":["podcast production","episode delivery","guest engagement","content pipeline","points system","meeting scheduling"],"overview":"- **Podcast Scheduling Changes:** Weekly calls paused next week due to travel; two episodes recorded this week; one released.  \n- **Client Engagement Success:** Positive feedback from clients like Joy Spain is creating new business opportunities and referrals.  \n- **Strong Download Metrics:** Over 40,000 downloads in last 90 days; 14,000 in last 30 days, showcasing audience engagement growth.  \n- **Resource Management Adjustments:** Meetings shifted to bi-weekly to manage workload; each meeting now utilizes five points to reduce strain.  \n- **Operational Efficiency Goals:** Adjustments aim to enhance workflow, prevent burnout, and maintain quality output amid resource constraints.","action_items":"\n**Gil**\nCancel the meeting scheduled for next week due to travel commitments (00:08)\nSend episode document to the team today (03:26)\nSend another episode document to the team tomorrow (03:26)\nContinue to improve guest communication and maintain pipeline for episodes through the end of the year (01:30)\n\n**Baylee Gunnell**\nFinalize and template new vertical clip format to implement for upcoming episodes, requiring one additional day (01:08)\nMonitor and report podcast download metrics regularly (04:14)\nAdjust meeting schedule to biweekly and reduce points allocation accordingly (05:08)\n"},"migrated_from":"contract_meetings","original_id":"5d805c4c-ca78-4c16-b79a-634c523b7bdf","master_marketer":{"status":"migrated"}}'::jsonb,
