  '[{"text":"Update final Arabic caption spelling to correct discrepancies in video project (01:52)","completed":false},{"text":"Send procurement video screenshot update for Jackie’s review post-meeting (02:42)","completed":false},{"text":"Prepare and send new Organic Social posts for review this week (02:54)","completed":false},{"text":"Restructure email outreach sequence focused on direct demo booking CTAs; send updated draft to Fahad and Jackie for input (07:20)","completed":false},{"text":"Send current outreach email sequence link to Jackie for ideation (13:55)","completed":false},{"text":"Create new LinkedIn paid media campaign reallocating $1500 from Google Ads budget to focus on demo landing page conversion (16:55)","completed":false},{"text":"Continue monitoring paid media performance and report stats weekly to clients (20:55)","completed":false},{"text":"Review procurement video updates and confirm accuracy of numbers/screenshots (02:41)","completed":false},{"text":"Provide input and ideate on shorter, more direct outreach email content incorporating impactful statistics and ISO certification (13:53)","completed":false},{"text":"Provide feedback on outreach messaging to ensure problem-solution orientation and relevance to target ICP (12:00)","completed":false},{"text":"Share example of demo outreach email that generated a response from 1 in 400 to help improve messaging practices (10:15)","completed":false},{"text":"Continue efforts to reschedule cancelled ABM demo and update team accordingly (03:50)","completed":false}]'::jsonb,
